class Solution:
    def sequentialDigits(self, low: int, high: int) -> List[int]:
        res = []
        for digits in range(len(str(low)), len(str(high)) + 1):
            for start in range(1, 11 - digits):
                num = int(''.join(str(start + i) for i in range(digits)))
                if low <= num <= high:
                    res.append(num)
        return sorted(res)
